// Firebase Cloud Messaging service worker. Templated -- the live file at
// /firebase-messaging-sw.js is generated by scripts/generate-sw.mjs from
// VITE_FIREBASE_* environment variables (see .env.example). Run `pnpm dev`
// or `pnpm build` to regenerate; the script also runs in CI.
//
// This SW also serves as the PWA install signal. Modern Chrome (99+) and
// the related install-prompt criteria no longer require a fetch handler;
// adding a no-op one triggers a console warning about navigation overhead.

importScripts("https://www.gstatic.com/firebasejs/10.14.0/firebase-app-compat.js");
importScripts("https://www.gstatic.com/firebasejs/10.14.0/firebase-messaging-compat.js");

firebase.initializeApp({
  apiKey: "__VITE_FIREBASE_API_KEY__",
  authDomain: "__VITE_FIREBASE_AUTH_DOMAIN__",
  projectId: "__VITE_FIREBASE_PROJECT_ID__",
  storageBucket: "__VITE_FIREBASE_STORAGE_BUCKET__",
  messagingSenderId: "__VITE_FIREBASE_MESSAGING_SENDER_ID__",
  appId: "__VITE_FIREBASE_APP_ID__",
});

const messaging = firebase.messaging();

messaging.onBackgroundMessage((payload) => {
  const title = payload.notification?.title ?? "Steward";
  const body = payload.notification?.body ?? "";
  self.registration.showNotification(title, {
    body,
    icon: "/icon.svg",
    badge: "/icon.svg",
    data: payload.data ?? {},
  });
});

/** Deep-link a notification tap into the matching in-app surface.
 *  Keep the `data.kind` map here in sync with the FCM payloads in
 *  functions/src/ (invitationResponseNotify, invitationReplyNotify,
 *  onCommentCreate). If an existing tab is already on our origin we
 *  focus + navigate that one; otherwise we open a new window. */
self.addEventListener("notificationclick", (event) => {
  event.notification.close();
  const url = routeForPushData(event.notification.data);
  if (!url) return;
  event.waitUntil(focusOrOpen(url));
});

function routeForPushData(data) {
  if (!data || typeof data !== "object") return "/";
  switch (data.kind) {
    case "invitation-response":
    case "invitation-reply":
      return data.invitationId
        ? `/schedule?chat=${encodeURIComponent(data.invitationId)}`
        : "/schedule";
    case "mention":
      return data.date ? `/week/${encodeURIComponent(data.date)}` : "/schedule";
    default:
      return "/";
  }
}

async function focusOrOpen(url) {
  const target = new URL(url, self.location.origin).href;
  const clients = await self.clients.matchAll({ type: "window", includeUncontrolled: true });
  for (const client of clients) {
    if (!client.url.startsWith(self.location.origin)) continue;
    if ("navigate" in client) {
      try {
        await client.navigate(target);
      } catch {
        // Some browsers reject cross-origin navigate; fall through to focus-only.
      }
    }
    return client.focus();
  }
  return self.clients.openWindow(target);
}
